@page "/apply"
@rendermode InteractiveServer
@using sv_0d58104a5f6548bbaa67b2347b5d333c.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="application-form">
    <h1>Job Application</h1>

    @* Step Indicator Bar *@
    <div class="step-indicator">
        @for (int i = 0; i < stepNames.Length; i++)
        {
            var stepIndex = i;
            var stepClass = GetStepClass(stepIndex);
            <div class="step @stepClass" @onclick="() => NavigateToStep(stepIndex)">
                <div class="step-circle">
                    @if (stepIndex < currentStep)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <div class="step-label">@stepNames[stepIndex]</div>
            </div>
            @if (i < stepNames.Length - 1)
            {
                <div class="step-connector @(i < currentStep ? "completed" : "")"></div>
            }
        }
    </div>

    @* Validation / Error Messages *@
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @* Step 1: Personal Info *@
    @if (currentStep == 0)
    {
        <div class="step-content">
            <h2>Personal Information</h2>
            <div class="form-group">
                <label for="fullName">Full Name *</label>
                <input id="fullName" type="text" class="form-control" @bind="fullName" />
            </div>
            <div class="form-group">
                <label for="email">Email *</label>
                <input id="email" type="email" class="form-control" @bind="email" />
            </div>
            <div class="form-group">
                <label for="phone">Phone *</label>
                <input id="phone" type="tel" class="form-control" @bind="phone" />
            </div>
            <div class="form-group">
                <label for="address">Address *</label>
                <input id="address" type="text" class="form-control" @bind="address" />
            </div>
            <div class="step-buttons">
                <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@isValidating">
                    @if (isValidating)
                    {
                        <span>Validating...</span>
                    }
                    else
                    {
                        <span>Next</span>
                    }
                </button>
            </div>
        </div>
    }

    @* Step 2: Work History *@
    @if (currentStep == 1)
    {
        <div class="step-content">
            <h2>Work History</h2>
            @for (int i = 0; i < workEntries.Count; i++)
            {
                var index = i;
                <div class="work-entry-card">
                    <h4>Position @(index + 1)</h4>
                    @if (workEntries.Count > 1)
                    {
                        <button class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                    }
                    <div class="form-group">
                        <label>Company Name *</label>
                        <input type="text" class="form-control" @bind="workEntries[index].Company" />
                    </div>
                    <div class="form-group">
                        <label>Job Title *</label>
                        <input type="text" class="form-control" @bind="workEntries[index].Title" />
                    </div>
                    <div class="form-row">
                        <div class="form-group half">
                            <label>Start Date *</label>
                            <input type="date" class="form-control" @bind="workEntries[index].StartDate" />
                        </div>
                        <div class="form-group half">
                            <label>End Date</label>
                            <input type="date" class="form-control" @bind="workEntries[index].EndDate" disabled="@workEntries[index].IsCurrent" />
                        </div>
                    </div>
                    <div class="form-group">
                        <label>
                            <input type="checkbox" @bind="workEntries[index].IsCurrent" /> Currently working here
                        </label>
                    </div>
                    <div class="form-group">
                        <label>Description *</label>
                        <textarea class="form-control" rows="3" @bind="workEntries[index].Description"></textarea>
                    </div>
                </div>
            }
            <button class="btn btn-secondary" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="step-buttons">
                <button class="btn btn-outline" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
            </div>
        </div>
    }

    @* Step 3: References *@
    @if (currentStep == 2)
    {
        <div class="step-content">
            <h2>References</h2>
            @for (int i = 0; i < references.Count; i++)
            {
                var index = i;
                <div class="reference-card">
                    <h4>Reference @(index + 1)</h4>
                    @if (references.Count > 2)
                    {
                        <button class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                    <div class="form-group">
                        <label>Name *</label>
                        <input type="text" class="form-control" @bind="references[index].Name" />
                    </div>
                    <div class="form-group">
                        <label>Relationship *</label>
                        <input type="text" class="form-control" @bind="references[index].Relationship" />
                    </div>
                    <div class="form-group">
                        <label>Email *</label>
                        <input type="email" class="form-control" @bind="references[index].Email" />
                    </div>
                    <div class="form-group">
                        <label>Phone *</label>
                        <input type="tel" class="form-control" @bind="references[index].Phone" />
                    </div>
                </div>
            }
            @if (references.Count < 3)
            {
                <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="step-buttons">
                <button class="btn btn-outline" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
            </div>
        </div>
    }

    @* Step 4: Cover Letter *@
    @if (currentStep == 3)
    {
        <div class="step-content">
            <h2>Cover Letter</h2>
            <div class="form-group">
                <label for="coverLetter">Write your cover letter *</label>
                <textarea id="coverLetter" class="form-control cover-letter-textarea" rows="12"
                          maxlength="2000" @bind="coverLetter" @bind:event="oninput"></textarea>
                <div class="character-count">@(coverLetter?.Length ?? 0) / 2000 characters</div>
            </div>
            <div class="step-buttons">
                <button class="btn btn-outline" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
            </div>
        </div>
    }

    @* Step 5: Review & Submit *@
    @if (currentStep == 4)
    {
        <div class="step-content">
            <h2>Review & Submit</h2>

            @if (isSubmitted)
            {
                <div class="confirmation">
                    <div class="confirmation-icon">&#10003;</div>
                    <h3>Application Submitted Successfully!</h3>
                    <p>Your application ID is: <strong>@applicationId</strong></p>
                    <p>Thank you for applying. We will review your application and get back to you.</p>
                </div>
            }
            else
            {
                <div class="review-section">
                    <div class="review-header">
                        <h3>Personal Information</h3>
                        <button class="btn btn-link" @onclick="() => GoToStep(0)">Edit</button>
                    </div>
                    <div class="review-content">
                        <p><strong>Name:</strong> @fullName</p>
                        <p><strong>Email:</strong> @email</p>
                        <p><strong>Phone:</strong> @phone</p>
                        <p><strong>Address:</strong> @address</p>
                    </div>
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h3>Work History</h3>
                        <button class="btn btn-link" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    <div class="review-content">
                        @foreach (var entry in workEntries)
                        {
                            <div class="review-work-entry">
                                <p><strong>@entry.Title</strong> at @entry.Company</p>
                                <p>@entry.StartDate.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))</p>
                                <p>@entry.Description</p>
                            </div>
                        }
                    </div>
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h3>References</h3>
                        <button class="btn btn-link" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    <div class="review-content">
                        @foreach (var reference in references)
                        {
                            <div class="review-reference">
                                <p><strong>@reference.Name</strong> (@reference.Relationship)</p>
                                <p>@reference.Email | @reference.Phone</p>
                            </div>
                        }
                    </div>
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h3>Cover Letter</h3>
                        <button class="btn btn-link" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <div class="review-content">
                        <p class="cover-letter-preview">@coverLetter</p>
                    </div>
                </div>

                <div class="step-buttons">
                    <button class="btn btn-outline" @onclick="Back">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isSubmitting">
                        @if (isSubmitting)
                        {
                            <span>Submitting...</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                </div>
            }
        </div>
    }
</div>

