+@code {
+    private readonly string[] stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+    private int currentStep = 0;
+    private string errorMessage = string.Empty;
+    private bool isValidating = false;
+    private bool isSubmitting = false;
+    private bool isSubmitted = false;
+    private int applicationId;
+
+    // Step 1 fields
+    private string fullName = string.Empty;
+    private string email = string.Empty;
+    private string phone = string.Empty;
+    private string address = string.Empty;
+
+    // Step 2 fields
+    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
+
+    // Step 3 fields
+    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
+
+    // Step 4 fields
+    private string coverLetter = string.Empty;
+
+    private string GetStepClass(int stepIndex)
+    {
+        if (stepIndex == currentStep) return "active";
+        if (stepIndex < currentStep) return "completed";
+        return "future";
+    }
+
+    private void NavigateToStep(int stepIndex)
+    {
+        if (stepIndex < currentStep)
+        {
+            currentStep = stepIndex;
+            errorMessage = string.Empty;
+        }
+    }
+
+    private void GoToStep(int step)
+    {
+        currentStep = step;
+        errorMessage = string.Empty;
+    }
+
+    private void Back()
+    {
+        if (currentStep > 0)
+        {
+            currentStep--;
+            errorMessage = string.Empty;
+        }
+    }
+
+    private async Task NextFromPersonalInfo()
+    {
+        errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
+            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
+        {
+            errorMessage = "Please fill in all required fields.";
+            return;
+        }
+
+        isValidating = true;
+        try
+        {
+            var isValidEmail = await ApplicationService.ValidateEmailAsync(email);
+            if (!isValidEmail)
+            {
+                errorMessage = "The email address is not valid. Please enter a valid email.";
+                return;
+            }
+            currentStep++;
+        }
+        finally
+        {
+            isValidating = false;
+        }
+    }
+
+    private void NextFromWorkHistory()
+    {
+        errorMessage = string.Empty;
+
+        foreach (var entry in workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
+                entry.StartDate == default || string.IsNullOrWhiteSpace(entry.Description))
+            {
+                errorMessage = "Please fill in all required fields for each work entry.";
+                return;
+            }
+        }
+        currentStep++;
+    }
+
+    private void NextFromReferences()
+    {
+        errorMessage = string.Empty;
+
+        foreach (var reference in references)
+        {
