.application-form {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
}

.application-form h1 {
    text-align: center;
    margin-bottom: 2rem;
}

/* Step Indicator */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #ccc;
    background: #fff;
    color: #999;
    transition: all 0.3s ease;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step.future .step-circle {
    opacity: 0.5;
}

.step-label {
    font-size: 0.75rem;
    margin-top: 0.4rem;
    text-align: center;
    color: #666;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.future .step-label {
    opacity: 0.5;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #ccc;
    margin: 0 0.5rem;
    margin-bottom: 1.2rem;
    max-width: 60px;
}

.step-connector.completed {
    background: #198754;
}

/* Form Styles */
.step-content {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 2rem;
}

.step-content h2 {
    margin-bottom: 1.5rem;
    color: #333;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    color: #555;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-control:focus {
    border-color: #0d6efd;
    outline: none;
    box-shadow: 0 0 0 2px rgba(13, 110, 253, 0.15);
}

.form-control:disabled {
    background: #f5f5f5;
    cursor: not-allowed;
}

.form-row {
    display: flex;
    gap: 1rem;
}

.form-group.half {
    flex: 1;
}

/* Cards for work entries and references */
.work-entry-card,
.reference-card {
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 1.5rem;
    margin-bottom: 1rem;
    position: relative;
    background: #fafafa;
}

.work-entry-card h4,
.reference-card h4 {
    margin-top: 0;
    margin-bottom: 1rem;
    color: #444;
}

.remove-btn {
    position: absolute;
    top: 1rem;
    right: 1rem;
}

/* Buttons */
.btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    transition: opacity 0.2s;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-success {
    background: #198754;
    color: #fff;
}

.btn-success:hover:not(:disabled) {
    background: #157347;
}

.btn-danger {
    background: #dc3545;
    color: #fff;
}

.btn-secondary {
    background: #6c757d;
    color: #fff;
}

.btn-outline {
    background: #fff;
    border: 1px solid #ccc;
    color: #333;
}

.btn-outline:hover {
    background: #f5f5f5;
}

.btn-link {
    background: none;
    color: #0d6efd;
    text-decoration: underline;
    padding: 0;
}

.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.85rem;
}

.btn-lg {
    padding: 0.75rem 2rem;
    font-size: 1.1rem;
}

.step-buttons {
    display: flex;
    justify-content: space-between;
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid #eee;
}

/* Alert */
.alert {
    padding: 0.75rem 1rem;
    border-radius: 4px;
    margin-bottom: 1rem;
}

.alert-danger {
    background: #f8d7da;
